def solve(n: Long, k: Long): Long = {
  if (k == 0) return 0

  val maxN = n.toInt
  val visited = Array.fill(maxN + 1)(-1)

  val queue = scala.collection.mutable.Queue[Int](1 to maxN.toList: _*)

  while (!queue.isEmpty) {
    val current = queue.dequeue
    val nextNum = popcount(current)
    if (nextNum == 1) {
      visited(current) = 1
    } else {
      visited(current) = visited(nextNum) + 1
      queue.enqueue(current)
    }
  }

  var count = 0L
  for (i <- 1 to maxN) {
    if (visited(i) == k) count += 1
  }
  count
}

